head.b:skin:
/*------------------------------------------------------------
PREMIUM NEWS GRADIENT COLOR VARIABLES (hadoti-news)
------------------------------------------------------------*/
:root {
    --primary-gradient: linear-gradient(135deg, #ff4500 0%, #ff007f 100%);
    --secondary-gradient: linear-gradient(135deg, #1e3c72 0%, #2a5298 100%);
    --dark-bg: #060913;
    --dark-card: #0f1626;
    --light-bg: #f5f7fb;
    --light-card: #ffffff;
    --text-main: #1e293b;
    --text-muted: #64748b;
    --accent-color: #ff4500;
    --font-global: 'Plus Jakarta Sans', 'Noto Sans Devanagari', sans-serif;
    --radius-prm: 14px;
    --shadow-prm: 0 12px 30px rgba(30, 60, 114, 0.08);
    --transition: all 0.35s cubic-bezier(0.25, 1, 0.5, 1);
}

body.dark-mode {
    --light-bg: var(--dark-bg);
    --light-card: var(--dark-card);
    --text-main: #f8fafc;
    --text-muted: #94a3b8;
    --shadow-prm: 0 15px 40px rgba(0, 0, 0, 0.5);
}

/* Core Layout Reset */
* { box-sizing: border-box; margin: 0; padding: 0; }
body { font-family: var(--font-global); background-color: var(--light-bg); color: var(--text-main); transition: var(--transition); overflow-x: hidden; }
a { color: inherit; text-decoration: none; transition: var(--transition); }
img { max-width: 100%; height: auto; display: block; border-radius: 8px; }

/* Reading Progress Tracker Bar */
#progress-bar { position: fixed; top: 0; left: 0; width: 0%; height: 4px; background: var(--primary-gradient); z-index: 99999; }

.container { max-width: 1260px; margin: 0 auto; padding: 0 20px; }

/* Breaking News Ticker Module */
.top-bar { background: #0a0f1d; color: #fff; padding: 12px 0; font-size: 13px; border-bottom: 1px solid rgba(255,255,255,0.05); }
.ticker-wrap { display: flex; align-items: center; justify-content: space-between; gap: 15px; }
.ticker-box { display: flex; align-items: center; overflow: hidden; width: 80%; }
.ticker-title { background: var(--primary-gradient); padding: 5px 14px; font-weight: 800; border-radius: 6px; margin-right: 15px; white-space: nowrap; font-size: 11px; letter-spacing: 0.5px; box-shadow: 0 4px 12px rgba(255, 69, 0, 0.3); }
.ticker-content { display: inline-block; white-space: nowrap; animation: ticker-live 30s linear infinite; color: #e2e8f0; }
@keyframes ticker-live { 0% { transform: translate3d(100%, 0, 0); } 100% { transform: translate3d(-100%, 0, 0); } }

/* Glassmorphic Sticky Header Navigation */
header { background: rgba(255, 255, 255, 0.9); backdrop-filter: blur(12px); -webkit-backdrop-filter: blur(12px); position: sticky; top: 0; z-index: 9999; box-shadow: 0 2px 20px rgba(0,0,0,0.03); transition: var(--transition); border-bottom: 1px solid rgba(0,0,0,0.03); }
body.dark-mode header { background: rgba(15, 22, 38, 0.9); border-bottom: 1px solid rgba(255,255,255,0.05); }
.header-inner { display: flex; justify-content: space-between; align-items: center; padding: 15px 0; }

/* Branding Logotype */
.logo h1 { font-size: 28px; font-weight: 800; background: var(--primary-gradient); -webkit-background-clip: text; -webkit-text-fill-color: transparent; letter-spacing: -0.5px; }

/* Portal Navigation Menu */
nav ul { display: flex; list-style: none; gap: 24px; }
nav ul li a { font-weight: 700; font-size: 15px; color: var(--text-main); padding: 6px 0; position: relative; }
nav ul li a::after { content: ''; position: absolute; bottom: 0; left: 0; width: 0; height: 3px; background: var(--primary-gradient); transition: var(--transition); border-radius: 2px; }
nav ul li a:hover::after { width: 100%; }

/* Action Triggers */
.nav-actions { display: flex; align-items: center; gap: 12px; }
.action-btn { width: 40px; height: 40px; border-radius: 50%; background: var(--light-bg); display: flex; align-items: center; justify-content: center; cursor: pointer; border: 1px solid rgba(0,0,0,0.04); transition: var(--transition); }
.action-btn:hover { background: var(--primary-gradient); color: #fff; transform: translateY(-2px); }

/* Grid Template Framework */
.main-wrapper { display: grid; grid-template-columns: 1fr; gap: 35px; margin-top: 35px; }
@media(min-width: 992px) { .main-wrapper { grid-template-columns: 2.4fr 1fr; } }

/* Core Feed - Multiple Items Grid */
.posts-grid { display: grid; grid-template-columns: 1fr; gap: 25px; }
@media(min-width: 600px) { .posts-grid { grid-template-columns: 1fr 1fr; } }

.card { background: var(--light-card); border-radius: var(--radius-prm); overflow: hidden; box-shadow: var(--shadow-prm); border: 1px solid rgba(0,0,0,0.02); display: flex; flex-direction: column; height: 100%; transition: var(--transition); }
.card:hover { transform: translateY(-6px); box-shadow: 0 20px 35px rgba(30, 60, 114, 0.15); }
.card-thumb { height: 210px; background: #e2e8f0; position: relative; overflow: hidden; }
.card-thumb img { width: 100%; height: 100%; object-fit: cover; transition: var(--transition); }
.card:hover .card-thumb img { transform: scale(1.06); }

.badge { position: absolute; top: 12px; left: 12px; background: var(--secondary-gradient); color: #fff; padding: 5px 12px; font-size: 11px; font-weight: 700; border-radius: 6px; text-transform: uppercase; }
.card-content { padding: 22px; flex-grow: 1; display: flex; flex-direction: column; justify-content: space-between; }
.card-meta { font-size: 12px; color: var(--text-muted); margin-bottom: 10px; display: flex; gap: 12px; font-weight: 600; }
.card-meta i { color: var(--accent-color); }
.card-title { font-size: 19px; font-weight: 700; line-height: 1.4; margin-bottom: 10px; color: var(--text-main); }
.card-text { font-size: 13.5px; color: var(--text-muted); line-height: 1.6; margin-bottom: 15px; }
.read-btn { font-weight: 700; font-size: 13.5px; color: var(--accent-color); display: inline-flex; align-items: center; gap: 6px; }

/*------------------------------------------------------------
COMPLEX NATIVE POST DETAILS PAGE STYLING 
------------------------------------------------------------*/
.post-body-container { background: var(--light-card); padding: 35px; border-radius: var(--radius-prm); box-shadow: var(--shadow-prm); border: 1px solid rgba(0,0,0,0.02); }
.post-main-title { font-size: 32px; font-weight: 800; line-height: 1.3; margin-bottom: 18px; color: var(--text-main); }
.breadcrumb-nav { display: flex; gap: 8px; font-size: 13px; color: var(--text-muted); margin-bottom: 20px; font-weight: 600; }
.post-content-inner { font-size: 16px; line-height: 1.8; color: var(--text-main); }
.post-content-inner p { margin-bottom: 18px; }
.post-content-inner h2, .post-content-inner h3 { margin: 30px 0 15px; font-weight: 800; }
.post-content-inner h2 { font-size: 24px; border-left: 4px solid var(--accent-color); padding-left: 12px; }

/* Social Share Area */
.share-container { display: flex; gap: 10px; margin: 25px 0; flex-wrap: wrap; }
.share-btn { padding: 8px 16px; border-radius: 6px; color: #fff; font-size: 13px; font-weight: 700; display: flex; align-items: center; gap: 8px; }
.share-fb { background: #3b5998; }
.share-tw { background: #1da1f2; }
.share-wa { background: #25d366; }

/* Native Comment System */
.comment-wrapper { margin-top: 40px; background: var(--light-card); padding: 30px; border-radius: var(--radius-prm); box-shadow: var(--shadow-prm); }

/*------------------------------------------------------------
ADVANCED SIDEBAR WIDGETS SYSTEM (Fully Re-engineered)
------------------------------------------------------------*/
.sidebar { display: flex; flex-direction: column; gap: 30px; }
.widget-container { background: var(--light-card); padding: 25px; border-radius: var(--radius-prm); box-shadow: var(--shadow-prm); border: 1px solid rgba(0,0,0,0.02); }
.widget-header-title { font-size: 15px; font-weight: 800; text-transform: uppercase; margin-bottom: 20px; position: relative; padding-bottom: 10px; letter-spacing: 0.5px; border-bottom: 2px solid rgba(0,0,0,0.04); }
.widget-header-title::after { content: ''; position: absolute; bottom: -2px; left: 0; width: 40px; height: 2px; background: var(--primary-gradient); }

/* 1. Native Search Form Box Widget CSS */
.search-widget-form form { display: flex; gap: 8px; }
.search-widget-input { flex-grow: 1; padding: 10px 14px; border: 1px solid rgba(0,0,0,0.08); border-radius: 6px; background: var(--light-bg); color: var(--text-main); font-weight: 500; outline: none; }
.search-widget-input:focus { border-color: var(--accent-color); }
.search-widget-submit { background: var(--primary-gradient); color: #fff; border: none; padding: 0 16px; border-radius: 6px; font-weight: 700; cursor: pointer; }

/* 2. Native Labels / Categories Widget CSS */
.label-cloud { display: flex; flex-wrap: wrap; gap: 8px; list-style: none; }
.label-cloud li a { display: block; background: var(--light-bg); padding: 6px 12px; font-size: 13px; font-weight: 600; border-radius: 6px; transition: var(--transition); border: 1px solid rgba(0,0,0,0.02); }
.label-cloud li a:hover { background: var(--primary-gradient); color: #fff; transform: translateY(-2px); }

/* 3. Native Profile (About Me) Widget CSS */
.profile-card { text-align: center; }
.profile-img { width: 85px; height: 85px; border-radius: 50%; margin: 0 auto 12px; border: 3px solid var(--accent-color); object-fit: cover; }
.profile-name { font-size: 16px; font-weight: 700; margin-bottom: 6px; }
.profile-bio { font-size: 13px; color: var(--text-muted); line-height: 1.5; margin-bottom: 12px; }
.profile-link { font-size: 12px; font-weight: 700; color: var(--accent-color); text-transform: uppercase; }

/* 4. Native Report Abuse & Attribution Widget CSS */
.report-abuse-link { font-size: 12px; font-weight: 600; color: var(--text-muted); text-decoration: underline; }
.report-abuse-link:hover { color: var(--accent-color); }

/* Premium Heavy Column Footer Structure */
footer { background: #04060d; color: #94a3b8; padding: 75px 0 30px; margin-top: 80px; border-top: 2px solid rgba(255, 69, 0, 0.2); }
.footer-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(240px, 1fr)); gap: 40px; margin-bottom: 45px; }
.footer-col h3 { color: #fff; margin-bottom: 20px; font-size: 19px; font-weight: 800; position: relative; }
.footer-col h3::after { content: ''; position: absolute; bottom: -6px; left: 0; width: 30px; height: 2.5px; background: var(--primary-gradient); }
.footer-col p { font-size: 13.5px; line-height: 1.8; }
.footer-menu { list-style: none; }
.footer-menu li { margin-bottom: 10px; font-size: 13.5px; font-weight: 600; }
.footer-menu li a:hover { color: #fff; padding-left: 4px; }

/* 100% Protected Original Copyright Area - hadoti-news */
.footer-bottom { border-top: 1px solid rgba(255,255,255,0.05); padding-top: 25px; text-align: center; font-size: 13.5px; font-weight: 600; color: #475569; }
.footer-bottom a { background: var(--primary-gradient); -webkit-background-clip: text; -webkit-text-fill-color: transparent; font-weight: 800; }

/* Back To Top UI Component */
#back-to-top { position: fixed; bottom: 30px; right: 30px; background: var(--primary-gradient); color: #fff; width: 44px; height: 44px; border-radius: 50%; display: none; align-items: center; justify-content: center; cursor: pointer; z-index: 9999; box-shadow: 0 8px 20px rgba(255, 69, 0, 0.35); border: none; transition: var(--transition); }
#back-to-top:hover { transform: translateY(-5px); }

body.script:
//
// 1. Fluid Dynamic Dark Mode Implementation Core Code
const darkToggleBtn = document.getElementById('dark-mode-switch');
const iconNode = darkToggleBtn.querySelector('i');
darkToggleBtn.addEventListener('click', () => {
    document.body.classList.toggle('dark-mode');
    if(document.body.classList.contains('dark-mode')) {
        iconNode.className = 'fas fa-sun';
    } else {
        iconNode.className = 'fas fa-moon';
    }
});

// 2. Reading Progress Indicator Line & Back To Top Tracker Logic Engine
window.addEventListener('scroll', () => {
    const currentScroll = document.body.scrollTop || document.documentElement.scrollTop;
    const documentTotalHeight = document.documentElement.scrollHeight - document.documentElement.clientHeight;
    const percentageProgress = (currentScroll / documentTotalHeight) * 100;
    document.getElementById('progress-bar').style.width = percentageProgress + '%';

    const bttContainer = document.getElementById('back-to-top');
    if(currentScroll > 400) { bttContainer.style.display = 'flex'; } else { bttContainer.style.display = 'none'; }
});

document.getElementById('back-to-top').addEventListener('click', () => {
    window.scrollTo({top: 0, behavior: 'smooth'});
});

// 3. Automated Localized Structural Live Calendar Watch Engine
document.getElementById('live-date-engine').innerText = new Date().toLocaleDateString('hi-IN', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
//
